const confirmYear=move=>{const{ok,nk,na}=yearDlg;let nh={...hist};if(move){nh[nk]=nh[ok];delete nh[ok];}setHist(nh);setAno(na);trig(nh,perfil,mes,na);setYearDlg(null);};
const tI=Object.values(mesData.ingresos||{}).reduce((a,b)=>a+(b||0),0)+(mesData.ingresosExtras||[]).reduce((a,b)=>a+(b.valor||0),0);
const tG=CATS_GAS.reduce((s,c)=>s+(mesData.gastos?.[c.id]?.total||0),0);
const tF=Object.values(mesData.fugas||{}).reduce((a,b)=>a+(b||0),0)+Object.values(mesData.fugasExtras||{}).reduce((a,cat)=>a+Object.values(cat||{}).reduce((s,e)=>s+(e.valor||0),0),0);
const tD=mesData.gastos?.deudas?.total||0;const bal=tI-tG;const pA=tI>0?(bal/tI)*100:0;const pD=tI>0?(tD/tI)*100:0;const pF=tI>0?(tF/tI)*100:0;
const getDiag=()=>{if(tI===0)return null;if(bal<0)return{tipo:'Gastos mayores a ingresos',color:C.red,icon:'🔴',desc:'Gastas más de lo que ganas.',acciones:['Lista todas tus deudas con monto y tasa','Elimina las 2 fugas más grandes esta semana','No adquieras ninguna deuda nueva','Escríbele a tu coach para un plan personalizado']};if(pD>35)return{tipo:'Deudas que ahogan',color:C.red,icon:'🔗',desc:'Tus cuotas consumen más del 35% del ingreso.',acciones:['Aplica el método avalancha','No uses tarjeta este mes','Destina ingresos extra a pagar deuda','Habla con tu coach sobre reestructuración']};if(pA<5&&pF>15)return{tipo:'Dinero que desaparece',color:C.yellow,icon:'🌀',desc:'Tu dinero se va en fugas antes de que puedas decidir.',acciones:['Cancela suscripciones inactivas','Tope semanal en efectivo','Programa ahorro el día del pago','Audita tu tarjeta']};if(pA<10)return{tipo:'Quiero ahorrar pero llego en cero',color:C.yellow,icon:'🎯',desc:'El problema es de orden, no de cantidad.',acciones:['El ahorro va primero — el día del pago','Crea cuenta separada de ahorro','Define una meta en la Brújula','Reduce una categoría variable']};return{tipo:'Finanzas saludables',color:C.green,icon:'✅',desc:'Vas bien. Foco en optimizar y crecer.',acciones:['Aumenta el ahorro al 20%','Considera CDT o fondo','Elimina fugas restantes','Activa una palanca de crecimiento']};};
