{yearDlg&&<div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.9)',zIndex:200,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}><div style={{background:C.card,borderRadius:16,padding:24,maxWidth:360,width:'100%',border:`1px solid ${C.border}`}}><div style={{fontFamily:'Syne,sans-serif',fontSize:15,fontWeight:800,color:'#fff',marginBottom:8}}>⚠️ Año diferente detectado</div><div style={{fontSize:13,color:C.muted,lineHeight:1.6,marginBottom:20}}>Tienes datos en <strong style={{color:C.text}}>{yearDlg.ok}</strong>. ¿Qué quieres hacer?</div><button onClick={()=>confirmYear(true)} style={{width:'100%',background:C.green,border:'none',borderRadius:10,padding:'12px',color:'#000',fontFamily:'Syne,sans-serif',fontSize:13,fontWeight:800,cursor:'pointer',marginBottom:8}}>Mover datos a {yearDlg.nk}</button><button onClick={()=>confirmYear(false)} style={{width:'100%',background:C.dark2,border:`1px solid ${C.border}`,borderRadius:10,padding:'12px',color:C.text,fontFamily:'Syne,sans-serif',fontSize:13,fontWeight:700,cursor:'pointer',marginBottom:8}}>Crear nuevo registro para {yearDlg.nk}</button><button onClick={()=>setYearDlg(null)} style={{width:'100%',background:'transparent',border:'none',color:C.muted,fontSize:12,cursor:'pointer'}}>Cancelar</button></div></div>}
